from dataclasses import dataclass, field, asdict

@dataclass
class Message:
    role: str
    content: str
    tokens: int = 0
    tags: list[str] = field(default_factory=list)

m = Message("user", "hello")
print(m)                       # Message(role='user', content='hello', tokens=0, tags=[])
print(asdict(m))               # {'role': 'user', 'content': 'hello', 'tokens': 0, 'tags': []}
